from fastapi import HTTPException


class AuthenticationError(HTTPException):
    """Raised when a request fails authentication (401)."""

    def __init__(self, message: str, status_code: int = 401):
        super().__init__(status_code=status_code, detail=message)


class NotFoundError(HTTPException):
    """Raised when a requested resource does not exist (404)."""

    def __init__(self, message: str, status_code: int = 404):
        super().__init__(status_code=status_code, detail=message)


class BadRequestError(HTTPException):
    """Raised when the client sends an invalid or malformed request (400)."""

    def __init__(self, message: str, status_code: int = 400):
        super().__init__(status_code=status_code, detail=message)


class UnprocessableEntityError(HTTPException):
    """Raised when input is well-formed but semantically invalid (422)."""

    def __init__(self, message: str, status_code: int = 422):
        super().__init__(status_code=status_code, detail=message)

